// Extract and prepare source code for integration test generation
const payload = $input.first().json;

const repository = payload.repository || 'owner/repo';
const branch = payload.branch || 'main';
const sourceFiles = payload.sourceFiles || [];
const testCode = payload.testCode || '';

return [{
  json: {
    repository,
    branch,
    owner: repository.split('/')[0],
    repo: repository.split('/')[1],
    sourceFiles,
    testCode,
    timestamp: new Date().toISOString()
  }
}];

