// Parse OpenAI response and extract generated tests
const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || '{}';

let parsed = {};
try {
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  parsed = jsonMatch ? JSON.parse(jsonMatch[0]) : {};
} catch (e) {
  parsed = { rawContent: content, parseError: e.message };
}

const tests = parsed.tests || [];
const summary = parsed.summary || {};

// Validate each generated test
const validatedTests = tests.map(test => ({
  ...test,
  isValid: !!(test.testCode && test.fileName),
  hasAssertions: test.testCode?.includes('assert') ||
                 test.testCode?.includes('Assert') ||
                 test.testCode?.includes('expect') ||
                 test.testCode?.includes('verify'),
  hasSetup: test.testCode?.includes('@BeforeEach') ||
             test.testCode?.includes('beforeEach') ||
             test.testCode?.includes('setup'),
  lineCount: test.testCode?.split('\n').length || 0
}));

const previousData = $('Prepare Input').first().json;

return [{
  json: {
    ...previousData,
    generatedTests: validatedTests,
    summary,
    totalGenerated: validatedTests.length,
    validTests: validatedTests.filter(t => t.isValid).length,
    tokensUsed: response.usage?.total_tokens || 0,
    parseError: parsed.parseError || null
  }
}];

