// Parse anti-pattern analysis response
const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || '{}';

let antiPatternReport = {};
try {
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  antiPatternReport = jsonMatch ? JSON.parse(jsonMatch[0]) : {};
} catch (e) {
  antiPatternReport = { issues: [], qualityScore: 0, parseError: e.message };
}

const previousData = $('Parse Generated Integration Tests').first().json;

return [{
  json: {
    ...previousData,
    antiPatternReport,
    qualityScore: antiPatternReport.qualityScore || 0,
    qualityGate: antiPatternReport.qualityGate || 'FAILED',
    issueCount: antiPatternReport.issues?.length || 0,
    criticalIssues: antiPatternReport.issues?.filter(i => i.severity === 'CRITICAL').length || 0
  }
}];

// Prepare files for GitHub commit
const data = $input.first().json;
const tests = data.generatedTests || [];

// Only commit valid tests
const validTests = tests.filter(t => t.isValid);

const filesToCommit = validTests.map(test => ({
  path: test.filePath || `src/test/java/generated/integration/${test.fileName}`,
  content: Buffer.from(test.testCode).toString('base64'),
  commitMessage: `test(integration): AI-generated - ${test.fileName}`
}));

return [{
  json: {
    ...data,
    filesToCommit,
    totalFilesToCommit: filesToCommit.length
  }
}];

// Prepare each file for individual commit
const branchData = $input.first().json;
const sha = branchData.object?.sha || branchData.sha;

const commitData = $('Prepare Commit Files').first().json;
const files = commitData.filesToCommit || [];

return files.map(file => ({
  json: {
    owner: commitData.owner,
    repo: commitData.repo,
    branch: commitData.branch,
    filePath: file.path,
    fileContent: file.content,
    commitMessage: file.commitMessage,
    sha
  }
}));

// Build Telegram failure notification with issues
const data = $input.first().json;
const issues = data.antiPatternReport?.issues || [];
const criticalIssues = issues.filter(i => i.severity === 'CRITICAL');

const issueLines = criticalIssues.slice(0, 5).map((issue, i) =>
  `${i + 1}. *${issue.pattern}* — ${issue.description}`
);

const message = [
  '❌ *Integration Tests — Quality Gate FAILED*',
  '',
  `📦 *Repository:* ${data.repository}`,
  `🌿 *Branch:* ${data.branch}`,
  '',
  '━━━━━━━━━━━━━━━━━━━━━━',
  '🔍 *Quality Analysis*',
  '━━━━━━━━━━━━━━━━━━━━━━',
  `• Quality Score: ${data.qualityScore}/100`,
  `• Quality Gate: ❌ ${data.qualityGate}`,
  `• Total Issues: ${data.issueCount}`,
  `• Critical Issues: ${data.criticalIssues}`,
  '',
  '⚠️ *Critical Issues Found:*',
  ...issueLines,
  '',
  '_Tests NOT committed — fix issues and retry_'
].join('\n');

return [{ json: { message, data } }];
